var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"대형 침식체 무력화 확인!","JPN":"大型の侵食体、無力化を確認！","ENG":"Large C.O. has been eliminated!","TWN":"確認大型侵蝕體失去攻擊性！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"측면의 기세도 눈에 띄게 약해졌다! 대열 정리하고 침착하게 대응해!","JPN":"側面の勢いも目に見えて弱くなっている！　隊列を整え、落ち着いて対応しろ！","ENG":"The forces on the sides have also got noticeably weaker! Maintain your formation and avoid making hasty decisions!","TWN":"側面的氣勢也明顯减弱！整軍後冷靜應對！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장님. 더 이상 적이 몰려오지 않습니다.","JPN":"隊長。もう敵が押し寄せてきません。","ENG":"Captain. They're no longer coming at us.","TWN":"隊長，敵人攻勢減緩。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이상하군.","JPN":"妙だな。","ENG":"That's odd.","TWN":"奇怪。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"嗯？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이 침식체들을 불러들인 놈이 모습을 드러내지 않았다.","JPN":"この侵食体を呼び寄せたやつが姿を現していない。","ENG":"We haven't found the person who summoned the C.O.s here.","TWN":"引來這些侵蝕體的傢伙竟然沒有露面。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식체의 대부분을 처리했는데도 모습을 드러내지 않았다는 건……","JPN":"侵食体のほとんどを倒したのに現れていないということは……","ENG":"We killed most of them. but seeing how she hasn't shown herself...","TWN":"我們已經除掉大部分的侵蝕體，她卻沒有出現……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…설마?","JPN":"……まさか？","ENG":"I got a bad feeling about this...","TWN":"…難道？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"사방의 숲이 전부 비슷하게 생겼는데, 제대로 가고 있는 게 맞나?","JPN":"周辺の森はすべて同じに見えるんだが、ちゃんと進んでいるのか？","ENG":"All I see is trees and grass. Are you sure we're going the right way?","TWN":"四周的樹林都長得好像，這樣走沒錯吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L14_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"걱정 마십시오. 저희들이 오랫동안 다니던 지름길입니다.","JPN":"ご心配なさいますな。わしらが長い間使ってきた近道です。","ENG":"No need to worry. This is a shortcut we've been using for a long time.","TWN":"你放心吧，我們一直以來都是走這條小路的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이대로 가다 보면 곧 도시가…","JPN":"このまままっすぐ行けばすぐ都市が……","ENG":"If we keep heading in this direction, a city should appear soo─","TWN":"繼續直走就會看到都市……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"…음?","JPN":"……む？","ENG":"Mm?","TWN":"…嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"왜 그러지?","JPN":"どうした？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이상하군요. 오래 전부터 이곳에 있던 부러진 나무가 보이지 않습니다.","JPN":"おかしいのう。昔からここにあった折れた木が見当たりません。","ENG":"Strange... I can’t see the broken tree that should be here.","TWN":"奇怪，怎麼沒看到很久之前就在這裡的樹枝。 "},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"촌장님, 이것 보세요. 저희가 방금 전에 부러뜨렸던 나뭇가지입니다.","JPN":"村長、これを見てください。私たちがさっき折った木の枝です。","ENG":"Chief, come look at this. This is a branch we just broke off.","TWN":"村長，你看，這是我們剛才折斷的樹枝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"믿기지 않지만…… 같은 곳을 맴돈 것 같아요.","JPN":"信じられませんが……同じところをぐるぐる回ってたみたいです。","ENG":"I don't want to believe it, but... I think we're going around in circles.","TWN":"真不敢相信……我們好像在鬼打牆。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그럴 리가……","JPN":"そんなはずは……","ENG":"It cannot be...","TWN":"怎麼會……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"다들 괜찮나?!","JPN":"みんな大丈夫か！？","ENG":"Is everyone all right?","TWN":"大家沒事吧？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"음? 지휘관님? 어떻게 여기까지 오신 겁니까?","JPN":"うむ？　指揮官？　ここまでどうやって？","ENG":"Huh? Commander? How did you get here so fast?","TWN":"嗯？指揮官？ 你怎麼來？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"걱정이 되어서 왔다. 침식체들을 쓰러뜨렸지만 그림자가 보이지 않더군.","JPN":"心配でな。侵食体を倒したが、シャドウが見当たらなかったんだ。","ENG":"I got worried, so I came as fast as I could. We defeated all the C.O.s, but the Shadow was nowhere to be seen.","TWN":"我有點擔心，處理掉侵蝕體後，竟然沒看到暗影。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"여긴 아직 아무 일 없었나?","JPN":"ここはまだなんともないか？","ENG":"Did anything happen?","TWN":"這裡沒發生什麼事吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"네, 그림자는 물론 침식체도 나타나지 않았습니다.","JPN":"はい。シャドウはおろか侵食体も現れておりません。","ENG":"No. We haven’t come across any Shadow, and no C.O. either for that part.","TWN":"沒有，沒有出現暗影，也沒有出現侵蝕體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"하지만… 어찌된 영문인지 숲에서 길을 잃은 것 같군요.","JPN":"ですが……どういうことか森で迷ってしまったようです。","ENG":"However... It seems that we are lost in the forest.","TWN":"但是… 不知怎麼回事，我們好像在樹林裡鬼打牆。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래. 늦지 않아 다행이군.","JPN":"そうか。遅くならなくて良かった。","ENG":"I see. I'm glad I’m not late.","TWN":"嗯，幸好還來得及。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"걱정 말도록. 함께 침착하게 길을 찾아 보지.","JPN":"心配するな。一緒に落ち着いて道を探してみよう。","ENG":"Don't worry. Let's all stay calm and find our way out.","TWN":"放心，我們一起找路吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관?","JPN":"指揮官？","ENG":"Commander?","TWN":"指揮官？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"네, 장교님.","JPN":"はい、将校。","ENG":"Yes, Officer Rashford.","TWN":"是，軍官。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"귀관은 오른팔이 부러져서 그 손으로 총을 쓰기 힘들지 않았나?","JPN":"貴官は右腕を骨折していて、そちらの手で銃は使えないのではなかったか？","ENG":"How's your right arm? Isn't it hard to shoot your gun with it being broken?","TWN":"你不是右手臂骨折，無法用手拿槍嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"괜찮습니다. 큰 부상도 아니었고, 어느 정도 나았으니까요.","JPN":"大丈夫です。大した怪我でもありませんでしたし、ある程度治りましたから。","ENG":"It's fine. It wasn't a big injury, and it's healed up pretty well now.","TWN":"沒事，傷勢不是很嚴重，已經恢復得差不多。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"거짓말이야. 사실 부러진 건 왼쪽 팔이다.","JPN":"嘘だな。骨折したのは左腕だ。","ENG":"Liar. It was your left arm that was broken.","TWN":"你騙人，骨折的其實左手臂。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네가 노리는 건 애초에 이쪽이었군.","JPN":"最初から貴様の狙いはこっちだったんだな。","ENG":"You were after us in the first place, weren't you?","TWN":"你的目標一開始就是這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아아, 아직 힘을 다루는 요령이 모자라나?","JPN":"ああ、まだ力を扱うコツがつかめてない感じ？","ENG":"Aah... I guess I need more practice.","TWN":"啊啊，使用力量的技巧還不夠純熟嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"원래 쓰던 카모플라주 슈트였으면 절대 안 들킬 자신 있었는데.","JPN":"元々使ってたカムフラージュスーツなら絶対バレない自信があったのに。","ENG":"If I was using my camouflage suit, I would've fooled you all.","TWN":"要是之前用的迷彩服，我有自信絕對不會被發現。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"방해하면 어떡해요, 래시포드 씨. 의지하게 만든 다음 다 죽여 버리려고 했단 말이에요.","JPN":"邪魔しないでください、ラッシュフォードさん。私を頼るよう仕向けておいて、皆殺しにしようと思ったのに。","ENG":"Why did you have to ruin my fun, Miss Rashford? I was going to make you rely on me before I killed you all.","TWN":"雷斯福特，你幹嘛妨礙我，我本是想騙過他們後，再把他們全都殺掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…빌어먹을 자식.","JPN":"……クソ野郎。","ENG":"Why you...!","TWN":"…該死的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"자, 그럼 눈치 없게 끼어든 대가를 치를 차례예요.","JPN":"さて、それじゃあ空気も読まずに割り込んだツケを払ってもらいますよ。","ENG":"Now, the time has come for you to pay the price for interrupting me.","TWN":"好，你這麼不長眼，我就好好教訓你一下吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"물론 얌전히 당하진 않으실 거죠? 제가 괴롭히는 동안 마음껏 발버둥쳐 주실 거죠? 네?","JPN":"もちろん大人しくやられたりしませんよね？　私がいじめてる間に、思いっきり足掻いてくれますよね？　ね？","ENG":"But you won't go down without a fight, right? You're going to squirm while I torture you, right?","TWN":"你肯定不會乖乖挨打的吧？我欺負你的時候，你會努力掙扎吧？會吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아야.","JPN":"いたっ。","ENG":"Ouch.","TWN":"哎呀。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"장교님에게서 떨어져라, 망할 그림자놈!","JPN":"将校から離れろ、クソシャドウ野郎！","ENG":"Get away from her, Shadow!","TWN":"離軍官遠一點，該死的暗影！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"안 돼……! 멈춰!","JPN":"ダメだ……！　やめろ！","ENG":"N-no...! Stop!","TWN":"不可以……！站住！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"끄헉……!","JPN":"くはっ……！","ENG":"Kuh...!","TWN":"咳呃……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L14_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"흐음… 이제 약골들 죽이는 걸론 별 감흥도 안 오네요.","JPN":"ふーん……もう弱いやつを殺すのでは満足できませんね。","ENG":"Hmm... Killing weaklings like you are no fun at all.","TWN":"嗯……現在殺死弱者一點也不覺得興奮呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"네 이놈!","JPN":"おのれ！","ENG":"Why you...!","TWN":"你這傢伙！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"네? 저요?","JPN":"はい？　私ですか？","ENG":"Hmm? Me?","TWN":"嗯？我嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"네가… 사람들을 그렇게 해치고도 무사할 줄 아느냐?","JPN":"お前さん……人をそんなに殺しておいて無事でいられると思っとるのか！","ENG":"Do you... think you can get away with murder?!","TWN":"你… 你以為你傷害那麼多人，還能全身而退嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"병든 노친네 주제에 절 쏘려고요? 방아쇠나 제대로 당길 수 있겠어요?","JPN":"病気になった年寄りのくせに私を撃つ気ですか？　引き金はちゃんと引けます？","ENG":"Are you going to shoot me, old man? Can you even pull the trigger?","TWN":"臭老頭，你是想開槍射我嗎？你有辦法扣扳機嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"평생 사냥꾼으로 살아온 몸이다! 너에게 한 방 먹이는 건 일도 아니지!","JPN":"一生狩人として生きてきたんでのう！　お前さんに一発食らわせるくらい朝飯前じゃ！","ENG":"I have been a hunter all my life! Putting a bullet in you would be like shooting fish in a barrel!","TWN":"我可是當了一輩子當獵人！讓你嚐嚐我的厲害！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"쿨럭……!","JPN":"ガハッ……！","ENG":"Krrgh...!","TWN":"咳咳……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지…… 지휘관?","JPN":"し……指揮官？","ENG":"C-Commander?","TWN":"指…… 指揮官？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이럴 수가…… 나, 나는 분명 저 괴물을 쐈을 텐데……?","JPN":"そんな……わ、わしは確かにあの化け物を撃ったはずじゃが……？","ENG":"It cannot be... I... I was certain I shot that monster...","TWN":"怎麼會這樣……我…我明明是要射那個怪物………？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아하하하하하!!","JPN":"アハハハハハハハッ！！","ENG":"Ahahahaha!!","TWN":"哈哈哈哈哈！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"래시포드 씨를 쐈을 때의 반응을 보고 싶었는데, 의외의 녀석이 대신 맞아 줬네.","JPN":"ラッシュフォードさんを撃った時の反応が見たかったのに、意外な人が代わりに撃たれてくれちゃったのね。","ENG":"I wanted to see the horror on your face when you shot her. But this'll do.","TWN":"我本來是想看看射雷斯福特時的反應，沒想到這傢伙竟然替她擋子彈。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아, 바로 이거야. 이런 재미있는 변주가 있어 줘야지.","JPN":"あ、そうよ、これよ。こんな面白い変奏が必要なわけ。","ENG":"Yes. That's it. I'm all for variation like this.","TWN":"啊，就是這個，就是要有這種有趣的變化才對。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관! 어째서…… 어째서 내 대신 총에 맞은 거냐……!","JPN":"指揮官！　なぜ……なぜ庇った……！","ENG":"Commander! Why... Why did you take that bullet for me...?!","TWN":"指揮官！為什麼……你為何要替我擋子彈……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"괜찮으신 것 같아… 다행이군요.","JPN":"大丈夫そうで……何よりです。","ENG":"I'm glad... that you're okay.","TWN":"幸好……你沒事。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"다들 귀관만 믿고 있었어! 그런데 왜 날 지키겠다고……!","JPN":"みんな貴官だけを信じているんだぞ！　なのになぜ私を守ろうとなど……！","ENG":"But everyone's counting on you! Why would you risk all that to save me...?!","TWN":"大家都只相信你！ 你為何要保護我…！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저는…… 오래 전 모든 걸 잃었습니다.","JPN":"私は……昔すべてを失いました。","ENG":"I've lost... everything a long time ago.","TWN":"我……在很久以前便失去一切。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"앞으로 남은 날도…… 그리 많지 않죠.","JPN":"残された日も……そう多くありません。","ENG":"And I don't... have many days left to live either.","TWN":"往後剩下的日子……也不多。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"잠깐만, 지휘관. 출혈이 너무 심해.","JPN":"待て、指揮官。出血がひどすぎる。","ENG":"Stop talking, Commander. You're bleeding too much.","TWN":"先別說話，指揮官，你失血過多。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"붕대…… 붕대가……","JPN":"包帯……包帯が……","ENG":"Bandages... Where are they...?","TWN":"繃帶…… 繃帶……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 장교님께선… 아직 이뤄야 할 게 많으시잖습니까?","JPN":"ですが、将校は……まだ成すべきことがたくさんあるではないですか。","ENG":"But you... You still have a lot to look forward to, no?","TWN":"但是軍官你不一樣…還有很多事在等著你去完成。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"빌어먹을! 헛소리 하지 말고 버텨!","JPN":"クソ！　馬鹿こと言ってないで持ちこたえるんだ！","ENG":"Shut up! Stop talking and stay with me!","TWN":"該死！別胡說，撐住！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"명령이다! 20년 전에도 운 좋게 살았다고 했잖아!","JPN":"命令だ！　20年前にも運よく生きのびたと言ったじゃないか！","ENG":"That's an order! You even survived out here for 20 years!","TWN":"這是命令！我不是說過你20年前也很幸運地活下來嗎！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"부디…… 살아남으십시오.","JPN":"どうか……生き残ってください。","ENG":"Please... Save yourself.","TWN":"你絕對……要活下去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"큐리안……? 정신 차려, 큐리안!!","JPN":"キュリアン……？　しっかりしろ、キュリアン！！","ENG":"Curian...? Curian! Wake up!!","TWN":"庫里安……？你振作一點，庫里安！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이렇게 허무하게 죽는 건 귀관의 계획이 아니잖아!","JPN":"こんな風に虚しく死ぬのが貴官の計画だったか？","ENG":"It wasn't your plan to die in vain like this!","TWN":"死得這麼莫名其妙不在你的計畫之內吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"어라? 큐리안이라니 무슨 말씀이세요?","JPN":"あれ？　キュリアンってどういうことですか？","ENG":"Hmm? Curian? What do you mean by that?","TWN":"嗯？你叫他庫里安？什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"총 한 방에 죽어 버리는 인간이 S급 카운터일 리 없잖아요?","JPN":"銃一発で死んでしまう人間が、Sランクのカウンターなわけないじゃないですか。","ENG":"There's no way a Grade S Counter would die from a measly bullet.","TWN":"一槍就斃命的人怎麼可能是S級制裁者？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그 사람은 오래 전에 죽었어요. 엘리시움의 최고 단원과 동귀어진하는 대신, 성유물을 망각 속에 묻어 버렸거든요.","JPN":"キュリアンならとうの昔に死にましたよ。エリシウムの首席奏者を道連れにして、聖遺物を忘却の彼方に葬ったんです。","ENG":"Plus, he's been dead for two decades. I know this because he chose to bury the Holy Relic while perishing with one of Elysium's Elite Members.","TWN":"那個人早就死咧？。他和愛樂的首席樂手一起同歸於盡，但是將聖遺物埋藏在遺忘中。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네가…… 그걸 어떻게?","JPN":"貴様が……なぜそれを？","ENG":"How... do you know that?","TWN":"你…… 怎麼會？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아아, 그렇군요.","JPN":"ああ、そう言えば。","ENG":"Oh, I see now.","TWN":"啊啊，原來如此。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"성유물을 찾으러 갔을 때 당신이 그 남자에게 성유물에 대해 물었던 것도…","JPN":"聖遺物を探しに行った時、あなたがその男に聖遺物について聞いたのも……","ENG":"The reason you asked him about the Holy Relic was also...","TWN":"去找聖遺物的時候，你也問過他有關聖遺物的事情…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그 남자를 큐리안이라고 믿고 있었기 때문이군요.","JPN":"その男がキュリアンだと信じていたからだったんですね。","ENG":"Because you believed that this man was Curian.","TWN":"原來你以為他是庫里安喔？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"오랫동안 같이 일한 저에게도 비밀로 하다니, 조금 배신당한 기분이랄까요?","JPN":"長い間一緒に働いてきた私にも内緒にするなんて、ちょっと裏切られた気分？","ENG":"I can't believe you kept that a secret from me. I almost feel a bit betrayed...","TWN":"我跟你一起共事這麼久，竟然都沒跟我說，有種不被信任的感覺嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"너…… 뭐가 그렇게 즐거운 거냐?","JPN":"貴様……何がそんなに楽しいんだ？","ENG":"Hey... What are you smirking about?","TWN":"你… 你在開心什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"내가 알던 한나라는 여자는 순진무구하고 호기심 많은 과학자일 뿐이었다.","JPN":"私の知るハンナという女は、純粋で好奇心旺盛な科学者に過ぎなかった。","ENG":"The Hanna I knew was nothing more than a naive and curious scientist.","TWN":"我所認識的漢娜是個天真無邪，好奇心很強的科學家。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런데 넌 대체 뭐지?","JPN":"だが、貴様はいったい何だ？","ENG":"But what are you?!","TWN":"但你到底是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"고작 사람들이 괴로워하며 죽는 꼴이나 보자고…… 그 악기를 찾은 건가?","JPN":"ただ人々が苦しみながら死んでいく様を見たいがために……その楽器を探したのか？","ENG":"You wanted to recover that instrument... just so you can watch people die in suffering?","TWN":"只因為想看人們痛苦地死去的樣子……所以才找那個樂器嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그딴 짓을 하는 네가……! 그림자와 다른 게 대체 뭐냔 말이다!","JPN":"そんなことをする貴様が……！　シャドウと何が違うというんだ！","ENG":"How does that...! Make you any different from Shadows?!","TWN":"做那種事的你……！跟暗影有何不同！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그렇게 말씀하시면 섭섭하죠. 저는 그저 <color=#ffd34c>버려진 형제들</color>을 위해 악기의 힘이 필요했을 뿐이에요.","JPN":"そんな風に言われたら悲しいじゃないですか。私はただ<color=#ffd34c>捨てられた兄弟</color>のために楽器の力が必要だっただけです。","ENG":"That's just hurtful. I wanted to find this because its power was needed for <color=#ffd34c>The Brothers Abandoned</color>.","TWN":"你這麼說我會難過的，我是因為<color=#ffd34c>被遺棄的兄弟們</color>才需要樂器的力量。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그리고 제 원래 이름은 한나가 아니라…","JPN":"それに、私の本当の名前はハンナじゃなくて……","ENG":"And my name isn't ”Hanna\\", it’s...","TWN":"還有我原本的名字不是漢娜…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"…어라?","JPN":"……あれ？","ENG":"...Huh?","TWN":"…嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그러고 보니 내 이름… 뭐였더라?","JPN":"そういえば、私の名前……何だっけ？","ENG":"Oh... Come to think of it... What is my name?","TWN":"話說回來，我…叫什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"크윽…?!","JPN":"くうっ……！？","ENG":"Krrgh...?!","TWN":"咳呃…？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"저쪽이다! 저쪽에서 장교님이 그림자 놈과 함께 있다!","JPN":"あそこだ！　将校がシャドウ野郎と一緒にいる！","ENG":"Over there! The Shadow is with Officer Rashford!","TWN":"在那邊！軍官和暗影在一起！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그림자를 저지해! 장교님을 해치게 두지 마라!","JPN":"シャドウを阻止しろ！　将校に危害を加えさせるな！","ENG":"Stop that Shadow! Don't let her hurt the officer!","TWN":"消滅暗影！別讓她傷害軍官！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"그림자…?","JPN":"シャドウ……？","ENG":"Shadow?","TWN":"暗影…？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"아니야……. 난 그림자 따위가 아니야……","JPN":"違う……私はシャドウなんかじゃない……","ENG":"That can't be... I'm not a Shadow...","TWN":"不是…我不是暗影……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CYMBALS_NPC_NULL_HANNA","text":{"KOREA":"……아니라고!!!","JPN":"……違う！！！","ENG":"You're wrong!!!","TWN":"……我不是！！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CYMBALS_NPC_NULL_HANNA","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RINGING"},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"사라졌어……?","JPN":"消えた……？","ENG":"S-she's gone...?","TWN":"消失了……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"지휘관님! 눈 좀 떠보세요!","JPN":"指揮官！　目を開けてください！","ENG":"Sir!! Wake up!","TWN":"指揮官！你醒醒！ "},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"망할… 대체 여기서 무슨 일이 벌어졌던 거야?","JPN":"くそ……ここでいったい何が起きたんだ？","ENG":"Dammit...! What happened here?!","TWN":"可惡… 剛才這裡到底發生什麼事？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…늦었어. 숨을 쉬지 않아.","JPN":"……もう遅い。息をしていない。","ENG":"We're too late. He's not breathing.","TWN":"…來不及了，沒呼吸了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장, 그게 무슨 소리예요? 지휘관님이 죽을 리가 없잖아요!","JPN":"隊長、どういうことですか？　指揮官が死ぬわけないじゃないですか！","ENG":"Captain, don't say that! There's no way he'd die like this!","TWN":"隊長，你在說什麼？指揮官怎麼可能會死！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"맞습니다, 대장님! 침식병으로 죽었으면 죽었지 이런 식으로 죽을 사람은 아니라고요!","JPN":"そうです、隊長！　侵食病ならともかく、こんな風に死ぬ人じゃないです！","ENG":"He's right, Captain! Maybe he would've died from the Corruption Syndrome, but not like this!","TWN":"沒錯，隊長！如果是因為侵蝕病死就算了，不可能會這樣死的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"내가 쐈네. 전부 내 탓이야.","JPN":"わしが撃った。全部わしのせいじゃ。","ENG":"I was the one who shot him. It's all my fault.","TWN":"是我開的槍，都怪我不好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"촌장님, 그게 무슨 말씀입니까?","JPN":"村長、どういうことですか？","ENG":"Chief...! You don't mean that...!","TWN":"村長，你這是什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"촌장님이 지휘관님을 쏘다니요? 대체 왜…?","JPN":"村長が指揮官を撃ったなんて、いったいどうして……？","ENG":"Chief shot our commander? But why...?","TWN":"村長對指揮官開槍？到底為什麼…？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그를 탓하지 마라.","JPN":"彼を責めるな。","ENG":"It wasn't his fault.","TWN":"別怪他。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그림자의 농간에 속은 거다. 촌장은 그림자를 쏘려고 했을 뿐이야.","JPN":"シャドウに翻弄されていた。村長はシャドウを撃とうとしただけだ。","ENG":"He was tricked by the Shadow. He was trying to shoot her.","TWN":"是暗影的把戲，村長原本只是想射暗影。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"……아니야.","JPN":"……違うんじゃ。","ENG":"No...","TWN":"……不。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"내가 장교님을 쏘려고 했어. 그걸 지휘관님이 막으려다……","JPN":"わしは将校を撃とうとしたんじゃ。指揮官はそれを止めようと……","ENG":"I tried to shoot Officer Rashford. And Commander tried to block it when─","TWN":"我原本是要朝軍官開槍，指揮官才會跳出來…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"다 내 잘못이야. 놈의 속임수인 게 뻔했는데… 눈앞에서 사람이 죽어나가니 그만…….","JPN":"全部わしのせいじゃ。やつの計略であることは明らかだったのに……目の前で人が死んでいくからつい……","ENG":"It's my fault. I knew what I saw wasn't real... But seeing all those people dying...","TWN":"都是我的錯，這擺明就是暗影的把戲…但看到有人在眼前死去，就……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"장교님, 놈이 어디로 갔는지, 보셨습니까?","JPN":"将校、やつがどこへ向かったかわかりますか？","ENG":"Officer, did you see where she went?","TWN":"軍官，你有看到他去哪裡嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한나는…….","JPN":"ハンナは……","ENG":"Hanna...","TWN":"漢娜……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아니, 그 괴물 녀석은 성유물이 어디 있는지 알아냈다고 했다. 아마도 악기의 기억을 통해 알아낸 거겠지.","JPN":"いや、あの化け物は聖遺物がどこにあるかわかったと言った。多分楽器の記憶を通じてわかったのだろう。","ENG":"No, I mean, that monster said she knew where the Holy Relic was buried. I'm sure she found out through the instrument's memories.","TWN":"不，那個怪物說，她知道聖物在哪裡，可能是透過樂器的記憶找到的吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아마 그곳으로 향했을 거야.","JPN":"多分そちらへ向かったはずだ。","ENG":"I think I know where she went.","TWN":"應該是往那個地方去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"놈은 성유물까지도 노리고 있었군요. 알겠습니다.","JPN":"やつは聖遺物までも狙っていたのですね。わかりました。","ENG":"So she's after the Holy Relic too. Understood.","TWN":"那傢伙連聖遺物也不放過嗎？好的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그렇다면 성유물은 어디에 있다는 거죠?","JPN":"だったら聖遺物はどこにあるんですか？","ENG":"Then where is the Holy Relic?","TWN":"那聖遺物在哪裡呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"놈이 말했다. 진짜 큐리안은 성유물을 지키기 위해 그림자와 동귀어진했다고.","JPN":"あいつはこう言った。本物のキュリアンは聖遺物を守るためにシャドウを道連れにしたと。","ENG":"She said it herself. The real Curian perished with a Shadow to protect the Holy Relic.","TWN":"她說真正的庫里安因為要守護聖遺物，而與暗影同歸於盡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"우리가 찾은 악기가 그림자의 것이라면, 성유물도 같은 곳 어딘가에 있겠지.","JPN":"我々が見つけた楽器がシャドウのものなら、聖遺物も同じ場所のどこかにあるのだろう。","ENG":"If that instrument we found is a Shadow's, then the Holy Relic should be somewhere over there.","TWN":"如果我們找到的樂器是暗影的，那聖遺物應該也在同一個地方的某處吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저희가 그 거대한 침식체를 파묻었던 곳이로군요.","JPN":"我々があの巨大な侵食体を埋めた場所ですね。","ENG":"Then it's where we buried that giant C.O.","TWN":"原來是在我們埋葬巨大侵蝕體的地方。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래. 하지만 우릴 유인하기 위해서 한 말일 가능성도 배제할 수 없다.","JPN":"そうだ。だが、我々をおびき寄せるための言葉である可能性も考えられる。","ENG":"Yes, but I can't shake the feeling that she only said that to lure us in.","TWN":"對，但也不排除是引誘我們過去的陷阱。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"함정이라고 하더라도 지금으로선 그게 유일한 단서입니다.","JPN":"罠だとしても今になってはそれが唯一の手がかりです。","ENG":"Even if it's a trap, it's our only lead at the moment.","TWN":"就算是陷阱，這也是現在唯一的線索。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"진짜 제라드 큐리안이라고?","JPN":"本物のジェラード・キュリアンだと？","ENG":"The \\"real\\" Gerard Curian?","TWN":"真正的傑瑞德· 庫里安？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"그럼 저희가 따르던 지휘관님은 누구란 겁니까?","JPN":"じゃあ、俺たちが従ってた指揮官は誰なんですか？","ENG":"Then who’s our commander??","TWN":"那我們跟隨的指揮官是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"정체 같은 건 아무래도 됐잖아요!","JPN":"正体なんてどうでもいいじゃないですか！","ENG":"Who cares who he really is?","TWN":"是什麼身分不重要！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"우리가 따르던 분이라고요! 어떻게라도 살려내야죠!","JPN":"僕たちが従ってきた方なんです！　なんとしてでも生き返らせないと！","ENG":"He is our commander! We can't let him die!","TWN":"重點他是我們跟隨的人！無論如何都要救活他！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"피터, 그만해. 이미 죽은 사람을 되살릴 수는 없어.","JPN":"ピーター、やめろ。死人を生き返らせることはできねえ。","ENG":"Peter, enough. There's no way to bring back the dead.","TWN":"彼得，別這樣，人死不能復生。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아니. 확실한 건 아니지만……","JPN":"いや、確実とは言えないけど……","ENG":"Wait... It's a long shot, but...","TWN":"不，雖然不是很確定…"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"방법이 있을지도 몰라.","JPN":"方法はあるかもしれない。","ENG":"There may be a way.","TWN":"但說不定會有辦法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"정말입니까? 대장이 의사라곤 하지만 그건 좀……","JPN":"本当ですか？　隊長が医者だとはいえ、それはちょっと……","ENG":"Really? But even if you're a doctor, that seems...","TWN":"真的嗎？雖然隊長是醫生，不過還是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그게 뭔데요? 말씀해 주세요, 대장님!","JPN":"何ですか？　おっしゃってください、隊長！","ENG":"So, what do we do? Tell us, Captain!","TWN":"是什麼辦法？請告訴我，隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"래시포드 장교님.","JPN":"ラッシュフォード将校。","ENG":"Officer Rashford.","TWN":"雷斯福特軍官，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"장교님의 도움이 필요합니다.","JPN":"将校の助けが必要です。","ENG":"We'll need your help as well.","TWN":"我需要你的幫助。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……말해 봐라.","JPN":"……話してみろ。","ENG":"All right.","TWN":"……說吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};